    name: 'Church of St. Lawrence (Malá Strana)',
    slug: 'kostel-sv-vavrence-mala-strana',
    localizedNames: { cz: 'Kostel sv. Vavřince (Malá Strana, Hellichova)', zh: '圣劳伦斯教堂（小城区）' },
