    name: 'Sternberg Palace',
    slug: 'sternbersky-palac',
    localizedNames: { cz: 'Šternberský palác', zh: '什切尔恩贝格宫' },
    labels: ['museum', 'palace', 'historical'],
    coordinates: { lat: 50.09037281238459, lng: 14.396663102923888 },
