    localizedNames: { cz: 'Zvonička Dačická', zh: '达奇茨卡钟塔（上梅霍卢皮）' },
    labels: ['historical', 'hidden-gem'],
    coordinates: { lat: 50.04690583476486, lng: 14.563017538497178 },
